81	// Determine if the input slice starts with a full valid opening delimiter.
82	// If so, returns the delimiter struct, otherwise returns nil.
83	func getFullOpeningDelimiter(delims []Delimiters, line []byte) *Delimiters {
84		for _, d := range delims {
85			if startsWith(line, d.Open) {
86				return &d
87			}
88		}
89	
90		return nil
91	}
92	
93	// Return an array of bytes containing the first byte of each opening
94	// delimiter. Used to populate the trigger list for inline and block parsers.
95	// `Parse` will be executed once for each character that is in this list of
96	// allowed trigger characters. Our parse function needs to do some additional
97	// checks because Trigger only works for single-byte delimiters.
98	func openersFirstByte(delims []Delimiters) []byte {
99		var firstBytes []byte
100		containsBackslash := false
101		for _, d := range delims {
102			if d.Open[0] == '\\' {
103				containsBackslash = true
104			}
105			firstBytes = append(firstBytes, d.Open[0])
106		}
107	
108		if !containsBackslash {
109			// always trigger on backslash because it can be used to escape the opening
110			// delimiter.
111			firstBytes = append(firstBytes, '\\')
112		}
113		return firstBytes
114	}
115	
116	// Determine if the input list of delimiters contains the given delimiter pair
117	func containsDelimiters(delims []Delimiters, toFind *Delimiters) bool {
118		for _, d := range delims {
119			if d.Open == toFind.Open && d.Close == toFind.Close {
120				return true
121			}
122		}
123	
124		return false
125	}
126	
127	// isInlineContainerNode returns true if n is a block-level node that contains
128	// inline content. Goldmark uses ast.KindParagraph for loose list items and
129	// standalone paragraphs, but ast.KindTextBlock for tight list items. Both need
130	// the same passthrough-splitting logic to ensure block delimiters render in
131	// display mode rather than inline.
132	func isInlineContainerNode(n ast.Node) bool {
133		if n == nil {
134			return false
135		}
136	
137		switch n.Kind() {
138		case ast.KindParagraph, ast.KindTextBlock:
139			return true
140		default:
141			return false
142		}
143	}
144	
145	func newInlineContainer(kind ast.NodeKind) ast.Node {
146		switch kind {
147		case ast.KindParagraph:
148			return ast.NewParagraph()
149		case ast.KindTextBlock:
150			return ast.NewTextBlock()
151		default:
152			return nil
153		}
154	}
155	
156	// trimContainerSpace removes leading or trailing whitespace from text nodes
157	// in a container, modifying the text segment boundaries in place.
158	func trimContainerSpace(container ast.Node, source []byte, leading bool) {
159		if container.ChildCount() == 0 {
160			return
161		}
162	
163		var textNode *ast.Text
164		if leading {
165			child := container.FirstChild()
166			if child.Kind() != ast.KindText {
167				return
168			}
169			textNode = child.(*ast.Text)
170		} else {
171			child := container.LastChild()
172			if child.Kind() != ast.KindText {
173				return
174			}
175			textNode = child.(*ast.Text)
176		}
177	
178		seg := textNode.Segment
179		value := seg.Value(source)
180		origLen := len(value)
181	
182		if leading {
183			value = bytes.TrimLeft(value, " \t")
184			newLen := len(value)
185			if newLen < origLen {
186				textNode.Segment = seg.WithStart(seg.Start + (origLen - newLen))
187			}
188		} else {
189			value = bytes.TrimRight(value, " \t")
190			newLen := len(value)
191			if newLen < origLen {
192				textNode.Segment = seg.WithStop(seg.Stop - (origLen - newLen))
193			}
194		}
195	}
