197	func (s *inlinePassthroughParser) Trigger() []byte {
198		return openersFirstByte(s.PassthroughDelimiters)
199	}
200	
201	func (s *inlinePassthroughParser) Parse(parent ast.Node, block text.Reader, pc parser.Context) ast.Node {
202		// In order to prevent other parser extensions from operating on the text
203		// between passthrough delimiters, we must process the entire inline
204		// passthrough in one execution of Parse. This means we can't use the style
205		// of multiple triggers with parser.Context state saved between calls.
206		line, startSegment := block.PeekLine()
207	
208		fencePair := getFullOpeningDelimiter(s.PassthroughDelimiters, line)
209		// fencePair == nil can happen if only the first byte of an opening delimiter
210		// matches, but it is not the complete opening delimiter. The trigger causes
211		// this Parse function to execute, but the trigger interface is limited to
212		// matching single bytes.
213		// It can also be because the opening delimiter is escaped with a
214		// double-backslash. In this case, we advance and return nil.
215		if fencePair == nil {
216			if len(line) > 2 && line[0] == '\\' && line[1] == '\\' {
217				fencePair = getFullOpeningDelimiter(s.PassthroughDelimiters, line[2:])
218				if fencePair != nil {
219					// Opening delimiter is escaped, return the escaped opener as plain text
220					// So that the characters are not processed again.
221					block.Advance(2 + len(fencePair.Open))
222					return ast.NewTextSegment(startSegment.WithStop(startSegment.Start + len(fencePair.Open) + 2))
223				}
224			}
225			return nil
226		}
227	
228		// This roughly follows goldmark/parser/code_span.go
229		block.Advance(len(fencePair.Open))
230		openerSize := len(fencePair.Open)
231		l, pos := block.Position()
232	
233		for {
234			line, lineSegment := block.PeekLine()
235			if line == nil {
236				block.SetPosition(l, pos)
237				return ast.NewTextSegment(startSegment.WithStop(startSegment.Start + openerSize))
238			}
239	
240			closingDelimiterPos := bytes.Index(line, []byte(fencePair.Close))
241			if closingDelimiterPos == -1 { // no closer on this line
242				block.AdvanceLine()
243				continue
244			}
245	
246			// This segment spans from the original starting trigger (including the delimiter)
247			// up to and including the closing delimiter.
248			seg := startSegment.WithStop(lineSegment.Start + closingDelimiterPos + len(fencePair.Close))
249			if seg.Len() == len(fencePair.Open)+len(fencePair.Close) {
250				return nil
251			}
252	
253			block.Advance(closingDelimiterPos + len(fencePair.Close))
254			return newPassthroughInline(seg, fencePair)
255		}
256	}
