302	type passthroughBlockRenderer struct{}
303	
304	func (r *passthroughBlockRenderer) renderRawBlock(w util.BufWriter, source []byte, n ast.Node, entering bool) (ast.WalkStatus, error) {
305		if entering {
306			l := n.Lines().Len()
307			for i := 0; i < l; i++ {
308				line := n.Lines().At(i)
309				w.WriteString(string(line.Value(source)))
310			}
311			w.WriteString("\n")
