315	
316	// To support the use of passthrough block delimiters in inline contexts, I
317	// wasn't able to get the normal block parser to work. Goldmark seems to only
318	// trigger the inline parser when the trigger is not the first characters in a
319	// block. So instead we hook into the transformer interface, and process an
320	// inline passthrough after it's parsed, looking for nodes whose delimiters
321	// match the block delimiters, and splitting the paragraph at that point.
322	type passthroughInlineTransformer struct {
323		BlockDelimiters []Delimiters
324	}
325	
326	var PassthroughInlineTransformer = &passthroughInlineTransformer{}
327	
328	const (
329		passthroughMarkedForDeletion = "passthrough_marked_for_deletion"
330		passthroughProcessed         = "passthrough_processed"
331	)
332	
333	// Note, this transformer destroys the RawText attributes of the paragraph
334	// nodes that it transforms. However, this does not seem to have an impact on
335	// rendering.
336	func (p *passthroughInlineTransformer) Transform(
337		doc *ast.Document, reader text.Reader, pc parser.Context,
338	) {
339		source := reader.Source()
340		// Goldmark's walking algorithm is simplistic, and doesn't handle the
341		// possibility of replacing the current node being walked with a new node. So
342		// as a workaround, we split the walk in two. The first walk inserts new
343		// nodes, and marks the original nodes for deletion. The second walk deletes
344		// the marked nodes. To avoid an infinite loop, we also need to mark the
345		// newly inserted nodes as "processed" so that they are not re-processed as
346		// the walk continues.
347		ast.Walk(doc, func(n ast.Node, entering bool) (ast.WalkStatus, error) {
348			if !entering || !isInlineContainerNode(n) {
349				return ast.WalkContinue, nil
350			}
351	
352			val, found := n.AttributeString(passthroughProcessed)
353			if found && val == "true" {
354				return ast.WalkContinue, nil
355			}
356	
357			// If no direct children are passthroughs, skip it.
358			foundInlinePassthrough := false
359			for c := n.FirstChild(); c != nil; c = c.NextSibling() {
360				if c.Kind() == KindPassthroughInline {
361					foundInlinePassthrough = true
362					break
363				}
364			}
365			if !foundInlinePassthrough {
366				return ast.WalkContinue, nil
367			}
368	
369			parent := n.Parent()
370			containerKind := n.Kind()
371			currentContainer := newInlineContainer(containerKind)
372			if currentContainer == nil {
373				return ast.WalkContinue, nil
374			}
375			// AppendChild breaks the link between the node and its siblings, so we
376			// need to manually track the current and next node.
377			currentNode := n.FirstChild()
378			insertionPoint := n
379	
380			for currentNode != nil {
381				nextNode := currentNode.NextSibling()
382				if currentNode.Kind() != KindPassthroughInline {
383					currentContainer.AppendChild(currentContainer, currentNode)
384					currentNode = nextNode
385				} else if currentNode.Kind() == KindPassthroughInline {
386					inline := currentNode.(*PassthroughInline)
387	
388					// Only split into a new block if the delimiters are block delimiters
389					if !containsDelimiters(p.BlockDelimiters, inline.Delimiters) {
390						currentContainer.AppendChild(currentContainer, currentNode)
391						currentNode = nextNode
392						continue
393					}
394	
395					newBlock := newPassthroughBlock(inline.Delimiters)
396					newBlock.SetPos(inline.Pos())
397					newBlock.Lines().Append(inline.Segment)
398					if currentContainer.ChildCount() > 0 {
399						// Trim trailing whitespace from text preceding the block in tight lists
400						if containerKind == ast.KindTextBlock {
401							trimContainerSpace(currentContainer, source, false)
402						}
403						// Trim leading whitespace from text following a previous block in tight lists
404						if containerKind == ast.KindTextBlock && insertionPoint.Kind() == KindPassthroughBlock {
405							trimContainerSpace(currentContainer, source, true)
406						}
407						parent.InsertAfter(parent, insertionPoint, currentContainer)
408						// Since we're not removing the original paragraph, we need to ensure
409						// that this paragraph is not re-processed as the walk continues
410						currentContainer.SetAttributeString(passthroughProcessed, "true")
411						insertionPoint = currentContainer
412					}
413					parent.InsertAfter(parent, insertionPoint, newBlock)
414					insertionPoint = newBlock
415					currentContainer = newInlineContainer(containerKind)
416					currentNode = nextNode
417				}
418			}
419	
420			if currentContainer.ChildCount() > 0 {
421				// Trim leading whitespace from text following a block in tight lists
422				if containerKind == ast.KindTextBlock && insertionPoint.Kind() == KindPassthroughBlock {
423					trimContainerSpace(currentContainer, source, true)
424				}
425				parent.InsertAfter(parent, insertionPoint, currentContainer)
426				// Since we're not removing the original paragraph, we need to ensure
427				// that this paragraph is not re-processed as the walk continues
428				currentContainer.SetAttributeString(passthroughProcessed, "true")
429			}
430	
431			// At this point, we don't remove the original paragraph, but mark it
432			// for removal in the second walk.
433			n.SetAttributeString(passthroughMarkedForDeletion, "true")
434			return ast.WalkContinue, nil
435		})
436	
437		// Now delete any marked nodes
438		ast.Walk(doc, func(n ast.Node, entering bool) (ast.WalkStatus, error) {
439			if !entering {
440				return ast.WalkContinue, nil
441			}
442	
443			for c := n.FirstChild(); c != nil; {
444				// Have to eagerly fetch this because `c` may be removed from the tree,
445				// destroying its link to the next sibling.
446				next := c.NextSibling()
447				if isInlineContainerNode(c) {
448					val, found := c.AttributeString(passthroughMarkedForDeletion)
449					if found && val == "true" {
450						n.RemoveChild(n, c)
451					}
452				}
453				c = next
454			}
455	
456			return ast.WalkContinue, nil
457		})
458	}
459	
460	func newPassthroughInlineTransformer(ds []Delimiters) parser.ASTTransformer {
461		return &passthroughInlineTransformer{
462			BlockDelimiters: ds,
463		}
464	}
465	
466	// RegisterFuncs implements renderer.NodeRenderer.RegisterFuncs.
467	func (r *passthroughInlineRenderer) RegisterFuncs(reg renderer.NodeRendererFuncRegisterer) {
468		reg.Register(KindPassthroughInline, r.renderRawInline)
469	}
470	
471	// RegisterFuncs implements renderer.NodeRenderer.RegisterFuncs.
472	func (r *passthroughBlockRenderer) RegisterFuncs(reg renderer.NodeRendererFuncRegisterer) {
473		reg.Register(KindPassthroughBlock, r.renderRawBlock)
474	}
475	
476	// ---- Extension and config ----
477	
478	type passthrough struct {
479		InlineDelimiters []Delimiters
480		BlockDelimiters  []Delimiters
481	}
482	
483	// Config configures this extension.
484	type Config struct {
485		InlineDelimiters []Delimiters
486		BlockDelimiters  []Delimiters
487	}
488	
489	func New(c Config) goldmark.Extender {
490		// The parser executes in two phases:
491		//
492		// Phase 1: parse the input with all delimiters treated as inline, and block delimiters
493		// taking precedence over inline delimiters.
494		//
495		// Phase 2: transform the parsed AST to split paragraphs at the point of
496		// inline passthroughs with matching block delimiters.
497		combinedDelimiters := make([]Delimiters, len(c.InlineDelimiters)+len(c.BlockDelimiters))
498		copy(combinedDelimiters, c.BlockDelimiters)
499		copy(combinedDelimiters[len(c.BlockDelimiters):], c.InlineDelimiters)
500		return &passthrough{
501			InlineDelimiters: combinedDelimiters,
502			BlockDelimiters:  c.BlockDelimiters,
503		}
504	}
505	
506	func (e *passthrough) Extend(m goldmark.Markdown) {
507		m.Parser().AddOptions(
508			parser.WithInlineParsers(
509				util.Prioritized(newInlinePassthroughParser(e.InlineDelimiters), 201),
510			),
511			parser.WithASTTransformers(
512				util.Prioritized(newPassthroughInlineTransformer(e.BlockDelimiters), 0),
513			),
514		)
515	
516		m.Renderer().AddOptions(renderer.WithNodeRenderers(
517			util.Prioritized(&passthroughInlineRenderer{}, 101),
518			util.Prioritized(&passthroughBlockRenderer{}, 99),
519		))
520	}
