var (
	tocResultKey = parser.NewContextKey()
	tocEnableKey = parser.NewContextKey()
)

type tocTransformer struct {
	r renderer.Renderer
}

func (t *tocTransformer) Transform(n *ast.Document, reader text.Reader, pc parser.Context) {
	if b, ok := pc.Get(tocEnableKey).(bool); !ok || !b {
		return
	}

	var (
		toc         tableofcontents.Builder
		tocHeading  = &tableofcontents.Heading{}
		level       int
		row         = -1
		inHeading   bool
		headingText bytes.Buffer
	)

	if ids := pc.IDs().(stringValuesProvider).StringValues(); len(ids) > 0 {
		toc.SetIdentifiers(ids)
	}

	ast.Walk(n, func(n ast.Node, entering bool) (ast.WalkStatus, error) {
		s := ast.WalkStatus(ast.WalkContinue)
		if n.Kind() == ast.KindHeading {
			if inHeading && !entering {
				tocHeading.Title = sanitizeTOCHeadingTitle(headingText.String())
				headingText.Reset()
				toc.AddAt(tocHeading, row, level-1)
				tocHeading = &tableofcontents.Heading{}
				inHeading = false
				return s, nil
			}

			inHeading = true
		}

		if !inHeading {
			return s, nil
		}

		if entering {
			switch n.Kind() {
			case ast.KindHeading:
				heading := n.(*ast.Heading)
				level = heading.Level

				if level == 1 || row == -1 {
					row++
				}

				id, found := heading.AttributeString("id")
				if found {
					tocHeading.ID = string(id.([]byte))
					tocHeading.Level = level
				}
			case
				ast.KindEmphasis,
				strikethroughAst.KindStrikethrough,
				extras.KindDelete,
				extras.KindInsert,
				extras.KindMark,
				extras.KindSubscript,
				extras.KindSuperscript:
				// Write opening tag for container inline nodes.
				// Don't skip children -- let the walker handle them,
				// which gracefully ignores unknown node types.
				writeOpeningInlineTag(&headingText, n)
			case
				ast.KindCodeSpan,
				ast.KindLink,
				ast.KindImage,
				emojiAst.KindEmoji,
				ast.KindAutoLink,
				ast.KindRawHTML,
				ast.KindText,
				ast.KindString:
				err := t.r.Render(&headingText, reader.Source(), n)
				if err != nil {
					return s, err
				}

				return ast.WalkSkipChildren, nil
			}
		} else {
			// Exiting a node inside a heading.
			switch n.Kind() {
			case
				ast.KindEmphasis,
				strikethroughAst.KindStrikethrough,
				extras.KindDelete,
				extras.KindInsert,
				extras.KindMark,
				extras.KindSubscript,
				extras.KindSuperscript:
				// Write closing tag for container inline nodes.
				writeClosingInlineTag(&headingText, n)
			}
		}

		return s, nil
	})

	pc.Set(tocResultKey, toc.Build())
}

type tocExtension struct {
	options []renderer.Option
}

func newTocExtension(options []renderer.Option) goldmark.Extender {
	return &tocExtension{
		options: options,
	}
}

func (e *tocExtension) Extend(m goldmark.Markdown) {
	r := goldmark.DefaultRenderer()
	r.AddOptions(e.options...)
	m.Parser().AddOptions(parser.WithASTTransformers(util.Prioritized(&tocTransformer{
		r: r,
	},
		// This must run after the ID generation (priority 100).
		110)))
}

var tocSanitizerPolicy = newTOCSanitizerPolicy()

// newTOCSanitizerPolicy returns a bluemonday policy for sanitizing TOC heading
// titles against an allowlist of inline HTML elements and attributes,
// specifically excluding anchor elements to prevent links within TOC heading
// titles.
func newTOCSanitizerPolicy() *bluemonday.Policy {
	p := bluemonday.NewPolicy()
	p.AllowElements(
		"abbr", "b", "bdi", "bdo", "br", "cite", "code", "data", "del", "dfn",
		"em", "i", "ins", "kbd", "mark", "q", "rp", "rt", "ruby", "s", "samp",
		"small", "span", "strong", "sub", "sup", "time", "u", "var", "wbr",
	)
	p.AllowStandardAttributes()
	p.AllowStyling()
	p.AllowImages()
	p.AllowAttrs("cite").OnElements("del", "ins", "q")
	p.AllowAttrs("datetime").OnElements("del", "ins", "time")
	p.AllowAttrs("value").OnElements("data")
	return p
}

var whiteSpaceRe = regexp.MustCompile(`\s+`)

// writeOpeningInlineTag writes the opening HTML tag for an inline container node.
func writeOpeningInlineTag(w *bytes.Buffer, n ast.Node) {
	tag := inlineTagName(n.Kind(), n)
	if tag == "" {
		return
	}
	fmt.Fprintf(w, "<%s>", tag)
}

// writeClosingInlineTag writes the closing HTML tag for an inline container node.
func writeClosingInlineTag(w *bytes.Buffer, n ast.Node) {
	tag := inlineTagName(n.Kind(), n)
	if tag == "" {
		return
	}
	fmt.Fprintf(w, "</%s>", tag)
}

// inlineTagName returns the HTML tag name for a given inline node kind.
func inlineTagName(kind ast.NodeKind, n ast.Node) string {
	switch kind {
	case ast.KindEmphasis:
		if n.(*ast.Emphasis).Level == 2 {
			return "strong"
		}
		return "em"
	case strikethroughAst.KindStrikethrough:
		return "del"
	case extras.KindDelete:
		return "del"
	case extras.KindInsert:
		return "ins"
	case extras.KindMark:
		return "mark"
	case extras.KindSubscript:
		return "sub"
	case extras.KindSuperscript:
		return "sup"
	default:
		return ""
	}
}

// sanitizeTOCHeadingTitle sanitizes s for use as a TOC heading title.
func sanitizeTOCHeadingTitle(s string) string {
	if strings.IndexByte(s, '<') == -1 {
		return s
	}

	// Sanitize the string.
	ss := tocSanitizerPolicy.Sanitize(s)

	// Remove extraneous whitespace.
	return whiteSpaceRe.ReplaceAllString(strings.TrimSpace(ss), " ")
}

